sql:
SELECT COUNT(opportunity_id) AS total_opportunities
FROM opportunities
WHERE event_id = 1 AND status = 0;

SELECT opportunity_name, description, max_volunteers
FROM opportunities
WHERE status = 1;

SELECT opportunity_id, COUNT(volunteer_id) AS volunteer_count
FROM volunteer_opportunities
GROUP BY opportunity_id;

SELECT COUNT(event_id) AS total_events
FROM events
WHERE event_date > '2023-10-01';

SELECT membership_status, COUNT(volunteer_id) AS volunteer_count
FROM volunteers
GROUP BY membership_status;

SELECT event_name, 
       CUME_DIST() OVER (ORDER BY event_type) AS type_rank
FROM events;

SELECT COUNT(opportunities.opportunity_id) AS total_opportunities, AVG(events.capacity) AS average_capacity
FROM opportunities
JOIN events ON opportunities.event_id = events.event_id;

external_knowledge:
- "leading stars" refers to the top volunteers;
- "shining a spotlight" implies highlighting or selecting;
- "trio" means the top 3 volunteers;
- "highest number of confirmed engagements" corresponds to the volunteers with the highest `confirmed_count`;
- "constellation of opportunities" represents the list of opportunities (`opportunity_names`) they have participated in.

sql:
SELECT COUNT(volunteer_id) AS volunteer_count
FROM volunteer_opportunities
WHERE opportunity_id = (SELECT opportunity_id FROM opportunities WHERE opportunity_name = 'Scoreboard');

SELECT COUNT(volunteer_id)
FROM volunteer_opportunities
WHERE opportunity_id = 0;

SELECT e.event_name, o.opportunity_name
FROM events e
JOIN opportunities o ON e.event_id = o.event_id;
